      children: `
        .dashboard-root { 
          padding: 28px; 
          font-family: Inter, system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue"; 
          background: #f3f6fb; 
          color: #0f172a; 
          min-height: 100vh;
          position: relative;
        }

        /* AI Chatbot Button */
        .ai-chatbot-button {
          position: fixed;
          bottom: 30px;
          right: 30px;
          width: 60px;
          height: 60px;
          border-radius: 50%;
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
          border: none;
          cursor: pointer;
          display: flex;
          align-items: center;
          justify-content: center;
          box-shadow: 0 8px 30px rgba(102, 126, 234, 0.4);
          z-index: 1000;
          transition: all 0.3s ease;
        }

        .ai-chatbot-button:hover {
          transform: scale(1.1);
          box-shadow: 0 12px 40px rgba(102, 126, 234, 0.6);
        }

        .ai-chatbot-button.has-unread {
          animation: pulse 2s infinite;
        }

        .unread-badge {
          position: absolute;
          top: -5px;
          right: -5px;
          background: #ef4444;
          color: white;
          font-size: 12px;
          font-weight: bold;
          width: 22px;
          height: 22px;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
        }

        @keyframes pulse {
          0% { box-shadow: 0 0 0 0 rgba(239, 68, 68, 0.7); }
          70% { box-shadow: 0 0 0 10px rgba(239, 68, 68, 0); }
          100% { box-shadow: 0 0 0 0 rgba(239, 68, 68, 0); }
        }

        /* Chatbot Modal */
        .chatbot-modal-overlay {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          background: rgba(0, 0, 0, 0.5);
          display: flex;
          align-items: center;
          justify-content: center;
          z-index: 9999;
          backdrop-filter: blur(4px);
        }

        .chatbot-modal {
          width: 90%;
          max-width: 500px;
          height: 80%;
          max-height: 700px;
          background: white;
          border-radius: 20px;
          overflow: hidden;
          box-shadow: 0 25px 50px rgba(0, 0, 0, 0.25);
          animation: modalSlideIn 0.3s ease-out;
        }

        @keyframes modalSlideIn {
          from {
            opacity: 0;
            transform: translateY(30px) scale(0.95);
          }
          to {
            opacity: 1;
            transform: translateY(0) scale(1);
          }
        }

        /* AI Stat Card */
        .ai-stat {
          cursor: pointer;
          transition: all 0.3s ease;
          position: relative;
          overflow: hidden;
        }

        .ai-stat:hover {
          transform: translateY(-2px);
          box-shadow: 0 8px 20px rgba(102, 126, 234, 0.3);
        }

        .ai-stat::before {
          content: '';
          position: absolute;
          top: 0;
          left: -100%;
          width: 100%;
          height: 100%;
          background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.2), transparent);
          transition: 0.5s;
        }

        .ai-stat:hover::before {
          left: 100%;
        }

        /* AI Prompt Card */
        .ai-prompt-card {
          border: 2px solid #e0e7ff;
          background: linear-gradient(135deg, #f8fafc 0%, #f1f5f9 100%);
        }

        .ai-prompt-header {
          display: flex;
          align-items: center;
          gap: 10px;
          margin-bottom: 15px;
          color: #4f46e5;
        }

        .ai-prompt-list {
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 10px;
        }

        .ai-prompt-btn {
          background: white;
          border: 1px solid #e2e8f0;
          border-radius: 8px;
          padding: 10px;
          font-size: 13px;
          color: #475569;
          cursor: pointer;
          transition: all 0.2s ease;
          text-align: center;
        }

        .ai-prompt-btn:hover {
          background: #e0e7ff;
          border-color: #6366f1;
          color: #4f46e5;
          transform: translateY(-1px);
        }

        /* Course AI Button */
        .course-ai-btn {
          margin-top: 10px;
          width: 100%;
          padding: 8px;
          background: #f8fafc;
          border: 1px solid #e2e8f0;
          border-radius: 6px;
          color: #64748b;
          font-size: 12px;
          cursor: pointer;
          transition: all 0.2s ease;
        }

        .course-ai-btn:hover {
          background: #e0e7ff;
          color: #4f46e5;
        }

        /* Quick Actions Footer */
        .quick-actions-footer {
          display: flex;
          gap: 12px;
          margin-top: 30px;
          padding-top: 20px;
          border-top: 1px solid #e2e8f0;
        }

        .btn.ai-action {
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
          display: flex;
          align-items: center;
          gap: 8px;
          margin-left: auto;
        }

        /* Existing styles with enhancements */
        .top-header { display:flex; justify-content: space-between; align-items: center; gap: 20px; margin-bottom: 20px;}
        .student-left { display:flex; gap: 16px; align-items:center; }
        .avatar { width:96px; height:96px; border-radius:12px; overflow:hidden; background:#fff; display:flex; align-items:center; justify-content:center; box-shadow: 0 6px 20px rgba(15,23,42,0.06);}
        .avatar img { width:100%; height:100%; object-fit:cover; }
        .initial { font-size:34px; font-weight:700; color:#0b1220; }
        .top-header h1 { margin:0; font-size:20px; }
        .sub { color:#475569; margin-top:4px;}
        .sub.small { font-size:12px; color:#64748b; margin-top:6px;}
        .badge { margin-top:8px; background:#eef2ff; color:#3730a3; padding:6px 8px; display:inline-block; border-radius:8px; font-weight:600; font-size:13px; }

        .right-stats { display:flex; gap:12px; align-items:center; }
        .stat { background:#fff; padding:12px 16px; border-radius:10px; box-shadow: 0 4px 10px rgba(2,6,23,0.04); text-align:center; min-width:120px;}
        .stat .label { font-size:12px; color:#64748b; }
        .stat .value { font-weight:700; font-size:18px; margin-top:6px; }

        .summary-cards { display:grid; grid-template-columns: 1fr 1fr 320px; gap:16px; margin-bottom: 20px; }
        .card { background:#fff; padding:16px; border-radius:12px; box-shadow: 0 6px 16px rgba(2,6,23,0.04); }
        .progress-line { width:100%; height:12px; background:#eef2ff; border-radius:999px; overflow:hidden; margin:12px 0;}
        .progress-line .fill { height:100%; background:#2563eb; transition: width 0.8s ease; border-radius:999px; }

        .metric-row { display:flex; justify-content:space-between; gap:12px; margin-top:12px; }
        .metric-label { color:#475569; font-size:12px; }
        .metric-value { font-weight:700; font-size:18px; }

        .btn { padding:8px 12px; border-radius:8px; background:#2563eb; color:white; border:none; cursor:pointer; font-size:14px; }
        .btn.alt { background:#10b981; }
        .btn.ghost { background:transparent; border:1px solid #e2e8f0; color:#0f172a; }

        .courses-section h2 { margin:0 0 12px 0; }
        .courses-grid { display:grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap:12px; }
        .course-card { background:#fff; padding:12px; border-radius:10px; border:1px solid #eef2ff; }
        .course-top { display:flex; justify-content:space-between; align-items:center; margin-bottom:8px; }
        .course-code { font-weight:700; color:#0f172a; }
        .course-name { color:#475569; margin-top:6px; }
        .course-meta { text-align:right; }
        .status { padding:6px 8px; border-radius:8px; font-size:12px; font-weight:700; display:inline-block;}
        .status.completed { background:#ecfeff; color:#065f46; }
        .status.enrolled { background:#eef2ff; color:#1e40af; }
        .status.dropped { background:#fff1f2; color:#9f1239; }
        .grade { font-weight:800; margin-top:8px; }

        .sem-table { background:#fff; padding:12px; border-radius:10px; margin-top:10px; }
        .row { display:grid; grid-template-columns: 60px 90px 80px 120px 220px 1fr; gap:12px; padding:8px 10px; align-items:center; border-bottom:1px solid #f1f5f9; }
        .row.header { font-weight:700; color:#0f172a; background:#f8fafc; border-bottom:1px solid #e6eefc; }
        .mini-course { font-size:13px; color:#475569; margin-bottom:6px; }

        .loader-container { height:100vh; display:flex; align-items:center; justify-content:center; }
        .loader-icon { width:56px; height:56px; color:#2563eb; animation: spin 1s linear infinite; }
        @keyframes spin { from{ transform:rotate(0);} to{ transform:rotate(360deg);} }

        .error-box { padding:20px; border-radius:12px; background:#fff1f2; color:#9f1239; margin:20px; }

        /* Responsive Design */
        @media (max-width: 1200px) {
          .summary-cards {
            grid-template-columns: 1fr 1fr;
          }
          .ai-prompt-card {
            grid-column: span 2;
          }
        }

        @media (max-width: 768px) {
          .summary-cards {
            grid-template-columns: 1fr;
          }
          .ai-prompt-card {
            grid-column: span 1;
          }
          .top-header {
            flex-direction: column;
            align-items: flex-start;
          }
          .right-stats {
            width: 100%;
            justify-content: space-between;
            flex-wrap: wrap;
          }
          .stat {
            min-width: calc(50% - 6px);
            margin-bottom: 12px;
          }
          .quick-actions-footer {
            flex-direction: column;
          }
          .btn.ai-action {
            margin-left: 0;
          }
        }
